            )
        })

        setupLaunchers()
        setupWebView()
        loadStartUrl()
    }

    private fun setupLaunchers() {
        cameraPermissionLauncher = registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
            if (granted) {
                webView.evaluateJavascript("window.NativeBridge && window.NativeBridge.onCameraPermissionResult(true);", null)
            } else {
                webView.evaluateJavascript("window.NativeBridge && window.NativeBridge.onCameraPermissionResult(false);", null)
            }
        }

        notificationPermissionLauncher = registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
