    @JavascriptInterface
    fun openCamera() {
        if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
            webView.post {
                webView.evaluateJavascript("window.NativeBridge && window.NativeBridge.onCameraReady();", null)
            }
        } else {
            if (activity is HybridWebViewActivity) {
                activity.runOnUiThread {
                    activity.cameraPermissionLauncher?.launch(Manifest.permission.CAMERA)
                }
            }
        }
    }

    @JavascriptInterface
    fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU) {
            webView.post {
                webView.evaluateJavascript("window.NativeBridge && window.NativeBridge.onNotificationPermissionResult(true);", null)
            }
            return
