        if (ContextCompat.checkSelfPermission(activity, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED) {
            webView.post {
                webView.evaluateJavascript("window.NativeBridge && window.NativeBridge.onNotificationPermissionResult(true);", null)
            }
        } else {
            if (activity is HybridWebViewActivity) {
                activity.runOnUiThread {
                    activity.notificationPermissionLauncher?.launch(Manifest.permission.POST_NOTIFICATIONS)
                }
            }
        }
    }

    @JavascriptInterface
    fun setItem(key: String, value: String) {
        val prefs = activity.getSharedPreferences("hybrid_web_storage", Context.MODE_PRIVATE)
        prefs.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun getItem(key: String): String {
        val prefs = activity.getSharedPreferences("hybrid_web_storage", Context.MODE_PRIVATE)
        return prefs.getString(key, "") ?: ""
    }

    @JavascriptInterface
    fun removeItem(key: String) {
        val prefs = activity.getSharedPreferences("hybrid_web_storage", Context.MODE_PRIVATE)
        prefs.edit().remove(key).apply()
    }

    @JavascriptInterface
    fun clearStorage() {
        val prefs = activity.getSharedPreferences("hybrid_web_storage", Context.MODE_PRIVATE)
        prefs.edit().clear().apply()
    }

    @JavascriptInterface
    fun postMessage(message: String) {
        try {
            val json = JSONObject(message)
            when (json.optString("type")) {
                "camera" -> openCamera()
                "notify" -> requestNotificationPermission()
